#include <iostream>
using namespace std;

class Base {
public:
 virtual void show() {
 cout << "Base::show() called" << endl;
 }
 virtual ~Base() {
 cout << "Base destructor" << endl;
 }
};

class Derived : public Base {
public:
 void show() override {
 cout << "Derived::show() called" << endl;
 }
 ~Derived() {
 cout << "Derived destructor" << endl;
 }
};

int main() {
 Base* ptr;
 Derived d;

 ptr = &d;
 ptr->show(); // Late binding - calls Derived::show()

 delete ptr; // Virtual destructor ensures proper cleanup
 return 0;
}

#include <iostream>
using namespace std;

class Calculator {
public:
 // Early binding - compiler resolves at compile time
 int add(int a, int b) {
 cout << "int add() called" << endl;
 return a + b;
 }

 double add(double a, double b) {
 cout << "double add() called" << endl;
 return a + b;
 }

 // Non-virtual function - early binding
 void display() {
 cout << "Display called" << endl;
 }
};

int main() {
 Calculator calc;
 calc.add(5, 3); // Early binding to int version
 calc.add(2.5, 3.7); // Early binding to double version
 calc.display(); // Early binding - static resolution
 return 0;
}

#include <iostream>
using namespace std;

// Abstract class - cannot be instantiated
class Shape {
protected:
 string color;
public:
 Shape(string c) : color(c) {}

 // Pure virtual function - must be overridden
 virtual void draw() = 0;

 // Virtual destructor
 virtual ~Shape() {}
};

class Circle : public Shape {
 double radius;
public:
 Circle(string c, double r) : Shape(c), radius(r) {}

 void draw() override {
 cout << "Drawing Circle with radius " << radius 
 << " in color " << color << endl;
 }
};

class Rectangle : public Shape {
 double length, width;
public:
 Rectangle(string c, double l, double w) : Shape(c), length(l), width(w) {}

 void draw() override {
 cout << "Drawing Rectangle " << length << "x" << width
 << " in color " << color << endl;
 }
};

int main() {
 // Shape s; // Error - cannot instantiate abstract class

 Shape* shapes[2];
 shapes[0] = new Circle("Red", 5.0);
 shapes[1] = new Rectangle("Blue", 10.0, 5.0);

 for(int i = 0; i < 2; i++) {
 shapes[i]->draw(); // Late binding - calls appropriate draw()
 }

 for(int i = 0; i < 2; i++) {
 delete shapes[i];
 }
 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 int x;
 virtual void show() {
 cout << "Base::show() x = " << x << endl;
 }
};

class Derived : public Base {
public:
 int y;
 void show() override {
 cout << "Derived::show() x = " << x << ", y = " << y << endl;
 }
};

int main() {
 Derived d;
 d.x = 10;
 d.y = 20;

 // Object slicing - derived part is lost
 Base b = d; // Slicing happens here!
 b.show(); // Calls Base::show()

 cout << "--- Using pointer to prevent slicing ---" << endl;

 // No slicing - using pointer
 Base* ptr = &d;
 ptr->show(); // Calls Derived::show() - late binding works!

 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 // Virtual destructor - ensures proper cleanup
 virtual ~Base() {
 cout << "Base destructor called" << endl;
 }
 virtual void display() {
 cout << "Base display" << endl;
 }
};

class Derived : public Base {
 int* data;
public:
 Derived() {
 data = new int[100]; // Dynamic memory allocation
 cout << "Memory allocated in Derived" << endl;
 }

 ~Derived() override {
 delete[] data; // Critical: frees allocated memory
 cout << "Derived destructor called - memory freed" << endl;
 }

 void display() override {
 cout << "Derived display" << endl;
 }
};

int main() {
 Base* ptr = new Derived();
 ptr->display();

 cout << "Deleting through base pointer..." << endl;
 delete ptr; // Virtual destructor ensures Derived destructor called first!

 return 0;
}
